CODE_EXAMPLE:
// Before
class Person {
  static final int O = 0;
  static final int A = 1;
  static final int B = 2;
  static final int AB = 3;
  private int bloodType;
}

// After
class BloodType {
  static final BloodType O = new BloodType(0);
  static final BloodType A = new BloodType(1);
  private int code;
  BloodType(int code) { this.code = code; }
}

class Person {
  private BloodType bloodType;
}

UNIT_TEST_EXAMPLE:
@Test
public void testTypeCodeWithClass() {
  Person person = new Person();
  person.setBloodType(BloodType.O);
  assertEquals(BloodType.O, person.getBloodType());
}
